import { Component, OnInit } from '@angular/core';
import { RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { NavbarComponent } from '../../components/navbar/navbar.component';
import { FooterComponent } from '../../components/footer/footer.component';
import { BookCardComponent, BookCard } from '../../components/book-card/book-card.component';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink, CommonModule, NavbarComponent, FooterComponent, BookCardComponent],
  templateUrl: './home.component.html',
})
export class HomeComponent implements OnInit {
  trendingBooks: BookCard[] = [];
  popularBooks: BookCard[] = [];

  ngOnInit() {
    this.trendingBooks = this.getMockBooks(4);
    this.popularBooks = this.getMockBooks(6);
  }

  getMockBooks(count: number): BookCard[] {
    const titles = [
      { t: 'Les Contes de Leuk-le-Lièvre', a: 'Léopold Sédar Senghor', p: 8000 },
      { t: 'Le Ventre de l\'Atlantique', a: 'Fatou Diome', p: 12000 },
      { t: 'Une si longue lettre', a: 'Mariama Bâ', p: 6000 },
      { t: 'Soundjata ou l\'épopée', a: 'Djibril Tamsir Niane', p: 9500 },
      { t: 'Mathématiques Terminale S', a: 'Seydou Traoré', p: 8500 },
      { t: 'L\'enfant noir', a: 'Camara Laye', p: 7500 },
    ];
    return Array.from({ length: count }, (_, i) => ({
      id: i + 1,
      title: titles[i % titles.length].t,
      author: titles[i % titles.length].a,
      price: titles[i % titles.length].p,
      condition: ['new', 'like_new', 'good', 'fair'][i % 4],
      book_type: 'novel',
      images: [{ url: `https://picsum.photos/seed/book${i+1}/300/400`, is_primary: true }],
      seller: { first_name: 'Fatou', last_name: 'Seck', phone: '+224123456789', address: 'Conakry' },
      is_available: true,
    }));
  }
}
